              let privateKey = keychain.loadPrivateKey(for: identifier),
              let publicKey = SecKeyCopyPublicKey(privateKey),
              let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, nil) as Data? else {
            return nil
        }
        
        let address = generateAddress(from: publicKeyData)
        let publicKeyHex = publicKeyData.map { String(format: "%02x", $0) }.joined()
        
        let wallet = CryptoWallet(address: address, publicKey: publicKeyHex, privateKeyRef: privateKey)
        currentWallet = wallet
        return wallet
    }
    
    private func generateAddress(from publicKey: Data) -> String {
        let hash = sha256(data: publicKey)
        let address = "0x" + hash.suffix(20).map { String(format: "%02x", $0) }.joined()
        return address
    }
    
    private func sha256(data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    func signTransaction(_ transaction: Transaction, completion: @escaping (Transaction?, Error?) -> Void) {
        BiometricAuthManager.shared.authenticateUser(reason: "Authenticate to sign transaction") { [weak self] success, error in
