                return
            }
            
            var signedTransaction = transaction
            signedTransaction.signature = signature.map { String(format: "%02x", $0) }.joined()
            completion(signedTransaction, nil)
        }
    }
    
    private func serializeTransaction(_ transaction: Transaction) -> Data {
        let string = "\(transaction.from)\(transaction.to)\(transaction.amount)\(transaction.nonce)\(transaction.gasPrice)\(transaction.gasLimit)"
        return string.data(using: .utf8) ?? Data()
    }
    
