    private func loadWallet() {
        if let wallet = walletManager.loadWallet() {
            displayWallet(wallet)
            refreshBalance()
        } else {
            createWalletButton.isHidden = false
            sendButton.isHidden = true
            refreshButton.isHidden = true
        }
    }
    
    private func displayWallet(_ wallet: CryptoWallet) {
        addressLabel.text = "Address: \(wallet.address)"
        createWalletButton.isHidden = true
        sendButton.isHidden = false
        refreshButton.isHidden = false
    }
    
    @objc private func createWalletTapped() {
        guard let wallet = walletManager.generateWallet() else {
            showAlert(title: "Error", message: "Failed to create wallet")
            return
        }
        
        displayWallet(wallet)
        refreshBalance()
        showAlert(title: "Success", message: "Wallet created successfully!\n\nAddress: \(wallet.address)")
    }
    
    @objc private func sendTransactionTapped() {
        let alert = UIAlertController(title: "Send Transaction", message: "Enter transaction details", preferredStyle: .alert)
        
        alert.addTextField { textField in
            textField.placeholder = "Recipient Address"
        }
        
        alert.addTextField { textField in
            textField.placeholder = "Amount"
            textField.keyboardType = .decimalPad
        }
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Send", style: .default) { [weak self] _ in
            guard let self = self,
                  let toAddress = alert.textFields?[0].text,
                  let amountString = alert.textFields?[1].text,
                  let amount = Double(amountString),
                  let wallet = self.walletManager.loadWallet() else {
                return
            }
            
            let transaction = Transaction(
                from: wallet.address,
                to: toAddress,
                amount: amount,
                nonce: Int(Date().timeIntervalSince1970),
                gasPrice: 0.0001,
                gasLimit: 21000,
                signature: nil
            )
            
            self.walletManager.signTransaction(transaction) { signedTransaction, error in
                if let error = error {
                    self.showAlert(title: "Error", message: "Failed to sign transaction: \(error.localizedDescription)")
                    return
                }
                
                guard let signedTransaction = signedTransaction else {
                    self.showAlert(title: "Error", message: "Failed to sign transaction")
                    return
                }
                
                self.blockchainService.broadcastTransaction(signedTransaction) { txHash, error in
                    DispatchQueue.main.async {
                        if let error = error {
                            self.showAlert(title: "Error", message: "Failed to broadcast transaction: \(error.localizedDescription)")
                            return
                        }
                        
                        self.showAlert(title: "Success", message: "Transaction sent!\nHash: \(txHash ?? "Unknown")")
                        self.refreshBalance()
                    }
                }
            }
        })
        
        present(alert, animated: true)
    }
    
    @objc private func refreshBalanceTapped() {
        refreshBalance()
    }
    
    private func refreshBalance() {
        guard let wallet = walletManager.loadWallet() else {
            return
        }
        
        blockchainService.getBalance(for: wallet.address) { [weak self] balance, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.balanceLabel.text = "Error loading balance"
                    return
                }
                
                self?.balanceLabel.text = String(format: "%.4f ETH", balance ?? 0.0)
            }
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

